func assignBodies(run *ddxgraphql.Run, bodies agent.SessionBodies) {
	if bodies.Prompt != "" {
		s := bodies.Prompt
		run.Prompt = &s
	}
	if bodies.Response != "" {
		s := bodies.Response
		run.Response = &s
	}
	if bodies.Stderr != "" {
		s := bodies.Stderr
		run.Stderr = &s
	}
}

